func UpdatedAtLTE(v time.Time) predicate.ConfigURIAttackPattern {
	return predicate.ConfigURIAttackPattern(sql.FieldLTE(FieldUpdatedAt, v))
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ConfigURIAttackPattern) predicate.ConfigURIAttackPattern {
	return predicate.ConfigURIAttackPattern(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ConfigURIAttackPattern) predicate.ConfigURIAttackPattern {
	return predicate.ConfigURIAttackPattern(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ConfigURIAttackPattern) predicate.ConfigURIAttackPattern {
	return predicate.ConfigURIAttackPattern(sql.NotPredicates(p))
}
